using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestHelpers
    {
        /// <summary>
        /// Creates a fresh InMemory SchoolContext with a unique database name.
        /// </summary>
        public static SchoolContext CreateInMemoryContext()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;
            return new SchoolContext(options);
        }

        /// <summary>
        /// Drains the static notification queue to prevent test interference.
        /// </summary>
        public static void DrainNotificationQueue()
        {
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
        }

        /// <summary>
        /// Seeds minimal test data into the context. Returns the seeded entities.
        /// </summary>
        public static SeedData SeedTestData(SchoolContext context)
        {
            var instructor = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = new DateTime(2000, 1, 15)
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var department = new Department
            {
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = instructor.ID
            };
            context.Departments.Add(department);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = department.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            var student = new Student
            {
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = new DateTime(2020, 9, 1)
            };
            context.Students.Add(student);
