using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void Setup()
    {
        _sut = new NotificationService();
        // Drain any leftover notifications from previous tests (static queue)
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        // Drain the queue after each test
        while (_sut.ReceiveNotification() != null) { }
        _sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_CreateOperation_EnqueuesNotification()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_IncludesNameInMessage()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_IncludesIdInMessage()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "42", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_GeneratesUpdateMessage()
    {
        // Arrange & Act
        _sut.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE, "Teacher");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
        Assert.AreEqual("UPDATE", notification.Operation);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
    {
        // Arrange & Act
        _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
        Assert.AreEqual("DELETE", notification.Operation);
    }

    [TestMethod]
    public void SendNotification_NoUserName_DefaultsToSystem()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithNullUserName_DefaultsToSystem()
    {
        // Arrange & Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, null);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
    {
        // Arrange
        _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
        _sut.SendNotification("Course", "2", "Second", EntityOperation.UPDATE);

        // Act & Assert - should come out in FIFO order
        var first = _sut.ReceiveNotification();
        Assert.AreEqual("Student", first.EntityType);
        Assert.AreEqual("1", first.EntityId);

        var second = _sut.ReceiveNotification();
        Assert.AreEqual("Course", second.EntityType);
        Assert.AreEqual("2", second.EntityId);

        // Queue should now be empty
        Assert.IsNull(_sut.ReceiveNotification());
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        // Arrange
        var before = System.DateTime.Now.AddSeconds(-1);

        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var after = System.DateTime.Now.AddSeconds(1);
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after,
            $"CreatedAt {notification.CreatedAt} should be between {before} and {after}");
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - MarkAsRead is a no-op but should not throw
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        var service = new NotificationService();
        service.Dispose();
        // Should not throw
    }

    [TestMethod]
    public void SendNotification_NullDisplayName_UsesIdFormat()
