    {
        // Arrange & Act
        _sut.SendNotification("Instructor", "7", "", EntityOperation.DELETE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Instructor (ID: 7) has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WhitespaceDisplayName_UsesIdFormat()
    {
        // Arrange & Act
        _sut.SendNotification("Instructor", "7", "   ", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Instructor (ID: 7) has been created", notification.Message);
    }
