+using Microsoft.AspNetCore.Mvc;
+
+namespace ContosoUniversity.Tests.Controllers;
+
+[TestClass]
+public sealed class NotificationsControllerTests
+{
+    private SchoolContext _context;
+    private NotificationsController _controller;
+
+    [TestInitialize]
+    public void Setup()
+    {
+        _context = TestHelpers.CreateInMemoryContext();
+        _controller = new NotificationsController(_context);
+        TestHelpers.DrainNotificationQueue();
+    }
+
+    [TestCleanup]
+    public void Cleanup()
+    {
+        _controller.Dispose();
+        _context.Dispose();
+        TestHelpers.DrainNotificationQueue();
+    }
+
+    [TestMethod]
+    public void Index_ReturnsViewResult()
+    {
+        // Act
+        var result = _controller.Index();
+
+        // Assert
+        Assert.IsInstanceOfType<ViewResult>(result);
+    }
+
+    [TestMethod]
+    public void GetNotifications_EmptyQueue_ReturnsEmptyList()
+    {
+        // Act
+        var result = _controller.GetNotifications();
+
+        // Assert
+        Assert.IsNotNull(result);
+        var jsonResult = result as JsonResult;
+        Assert.IsNotNull(jsonResult);
+
+        // Verify the response has success = true and count = 0
+        dynamic value = jsonResult.Value;
+        Assert.IsNotNull(value);
+    }
+
+    [TestMethod]
+    public void GetNotifications_WithNotifications_ReturnsNotifications()
+    {
+        // Arrange - send some notifications via the service
+        var svc = new NotificationService();
+        svc.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");
+        svc.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE, "Teacher");
+
+        // Act
+        var result = _controller.GetNotifications() as JsonResult;
+
+        // Assert
+        Assert.IsNotNull(result);
+        Assert.IsNotNull(result.Value);
+    }
+
+    [TestMethod]
+    public void GetNotifications_ReturnsJsonResult()
+    {
+        // Act
+        var result = _controller.GetNotifications();
+
+        // Assert
+        Assert.IsInstanceOfType<JsonResult>(result);
+    }
+
+    [TestMethod]
+    public void MarkAsRead_ReturnsJsonResult()
+    {
+        // Act
+        var result = _controller.MarkAsRead(1);
+
+        // Assert
+        Assert.IsInstanceOfType<JsonResult>(result);
+    }
+
+    [TestMethod]
+    public void MarkAsRead_ValidId_ReturnsSuccess()
+    {
+        // Act
+        var result = _controller.MarkAsRead(1) as JsonResult;
+
+        // Assert
+        Assert.IsNotNull(result);
+        Assert.IsNotNull(result.Value);
+    }
+
+    [TestMethod]
+    public void GetNotifications_LimitsToTenNotifications()
+    {
+        // Arrange - send 15 notifications
+        var svc = new NotificationService();
+        for (int i = 0; i < 15; i++)
+        {
+            svc.SendNotification("Student", i.ToString(), EntityOperation.CREATE, "Admin");
+        }
+
+        // Act
+        var result = _controller.GetNotifications() as JsonResult;
+
+        // Assert
+        Assert.IsNotNull(result);
+        // The controller limits to 10 notifications max
+        Assert.IsNotNull(result.Value);
+    }
+}
